        if type(k) == str:
            if not k.islower() and not k.isupper():
                return False
        else:
            return False

    # check for upper and lower case
    for k in dict:
        if type(k) == str:
            if not k.islower() and not k.isupper():
                return False
        else:
            return False
    return True

