def maximum(arr, k):
    """
    Given an array arr of integers and a positive integer k, return a sorted list 
    of length k with the maximum k numbers in arr.

    Example 1:

        Input: arr = [-3, -4, 5], k = 3
        Output: [-4, -3, 5]

    Example 2:

        Input: arr = [4, -4, 4], k = 2
        Output: [4, 4]

    Example 3:

        Input: arr = [-3, 2, 1, 2, -1, -2, 1], k = 1
        Output: [2]

    Note:
        1. The length of the array will be in the range of [1, 1000].
        2. The elements in the array will be in the range of [-1000, 1000].
        3. 0 <= k <= len(arr)
    """

    # Time complexity: O(n * log(k))
    # Space complexity: O(k)
    def partition(arr, low, high):
        pivot = arr[high]
        i = low
        for j in range(low, high):
            if arr[j] > pivot:
                arr[i], arr[j] = arr[j], arr[i]
                i += 1
        arr[i], arr[high] = arr[high], arr[i]
        return i

    def find_k_largest(arr, k):
        n = len(arr)
        if k > n:
            raise ValueError('k cannot be greater than length of array')
        elif k == n:
            return arr
        elif k == 1:
            return max(arr)
        else:
            pivot_idx = partition(arr, 0, n - 1)
            if pivot_idx + 1 == k:
                return arr[:k]
            elif pivot_idx + 1 > k:
                return find_k_largest(arr[:pivot_idx + 1], k)
            else:
                return find_k_largest(arr[pivot_idx + 1:], k - pivot_idx - 1)

    return find_k_largest(arr, k)

